function solve(s) {
    const N = s.length;
    if (N === 0) {
        return 0;
    }

    // 1. Precompute PC_0: Prefix count of '0's
    const PC_0 = new Array(N);
    let currentZeros = 0;
    for (let i = 0; i < N; i++) {
        if (s[i] === '0') {
            currentZeros++;
        }
        PC_0[i] = currentZeros;
    }
    const totalZeros = PC_0[N - 1];
    const totalOnes = N - totalZeros;

    // 2. & 3. Initialize structures
    // P[i] is the balance up to index i. Map: balance -> smallest index j such that P[j] = balance.
    // We use index j = -1 to represent the conceptual prefix before index 0, where P[-1] = 0.
    const firstOccurrence = new Map();
    firstOccurrence.set(0, -1);

    let max_length = 0;
    let currentBalance = 0;

    // 5. Iterate b from 0 to N-1
    for (let b = 0; b < N; b++) {
        // Calculate P_b
        currentBalance += (s[b] === '1' ? 1 : -1);

        // Helper to calculate counts for s[j+1...b]
        // j is the previous index stored in firstOccurrence
        const getCounts = (j) => {
            const L = b - j;
            // C_0(a, b) = PC_0[b] - PC_0[j]
            const c0 = (j === -1) ? 0 : PC_0[b] - PC_0[j];
            const c1 = L - c0;
            return { c0, c1, L };
        };

        // Check Case D=0 (No swap needed): P_b = P_j
        if (firstOccurrence.has(currentBalance)) {
            const j = firstOccurrence.get(currentBalance);
            const { L } = getCounts(j);
            max_length = Math.max(max_length, L);
        }

        // Check Case D=2: P_j = P_b - 2. Imbalance +2 (Too many ones). Need 1 -> 0 swap inside.
        const targetT_D2 = currentBalance - 2;
        if (firstOccurrence.has(targetT_D2)) {
            const j = firstOccurrence.get(targetT_D2);
            const { c0, c1, L } = getCounts(j);

            // D=2 means C1 = C0 + 2. We need an external '0' to swap with an internal '1'.
            // Required external '0's > 0.
            const externalZeros = totalZeros - c0;
            if (externalZeros > 0) {
                max_length = Math.max(max_length, L);
            }
        }

        // Check Case D=-2: P_j = P_b + 2. Imbalance -2 (Too many zeros). Need 0 -> 1 swap inside.
        const targetT_D_2 = currentBalance + 2;
        if (firstOccurrence.has(targetT_D_2)) {
            const j = firstOccurrence.get(targetT_D_2);
            const { c0, c1, L } = getCounts(j);

            // D=-2 means C0 = C1 + 2. We need an external '1' to swap with an internal '0'.
            // Required external '1's > 0.
            const externalOnes = totalOnes - c1;
            if (externalOnes > 0) {
                max_length = Math.max(max_length, L);
            }
        }

        // Update first occurrence
        if (!firstOccurrence.has(currentBalance)) {
            firstOccurrence.set(currentBalance, b);
        }
    }

    return max_length;
}

